#include <iostream>
#include <string>
using namespace std;

// 1. Маленький незалежний клас. 
// Ним можна користуватись будь-де.
class Engine {
private:
    int horsepower;
    string type;
public:
    Engine(int hp, string t) : horsepower(hp), type(t) {
        // Двигун створено.
    }

    void start() const {
        cout << "[Двигун] ВРРРУМММ! " << horsepower << " конячих сил!" << endl;
    }

    // Геттер
    string getType() const { return type; }
};

// 2. ВЕЛИКИЙ КЛАС.
// Він буде МІСТИТИ у собі об'єкт Engine через композицію.
class Car {
private:
    string brand;
    Engine motor; // Композиція (Car HAS A Engine)

public:
    // Конструктор приймає дані для самого себе, та дані ДЛЯ СВОГО ДВИГУНА.
    // Ми ПЕРЕДАЄМО параметри мотора у `motor(...)` в стрічці ініціалізації.
    Car(string b, int engHp, string engName)
        : brand(b), motor(engHp, engName) 
    {
    }

    void drive() {
        cout << "
Водій повертає ключ в своєму " << brand << "..." << endl;
        // Автомобіль делегує роботу своєму двигуну!
        motor.start();
        cout << "Тип вашого агрегату: " << motor.getType() << endl;
        cout << "Ми успішно поїхали." << endl;
    }
};

int main() {
    // Я створюю авто, але в ньому автоматично створюється справжній об'єкт Двигуна!
    Car myCar("BMW M5", 600, "TwinTurbo V8");
    myCar.drive();

    Car ecoCar("Nissan Leaf", 147, "Electric EV");
    ecoCar.drive();

    return 0;
}
